const express = require('express');
const cors = require('cors');

const app = express();

app.use(cors());
app.use(express.json());


// Allow specific Domain
app.use(cors({
    origin: "http://localhost:3000",
}))

const PORT = 3000;


app.get("/", (req, res) => {
    res.send("API is running...!");
});

app.listen(PORT, ()=> {
        console.log("Server is running...!" + PORT);
})